const fs = require("fs");
const path = require("path");

const PATCH_NAME = "BARNDAKSA_CUSTOMER_FAST_APP_BUTTONS_HOTFIX";
const PATCH_PAYLOAD = [{
  path: "components/customer-app/customer-fast-app-client.tsx",
  encoding: "base64",
  content: ""
}];
const PATCH_MANIFEST = {
  "name": "BARNDAKSA_CUSTOMER_FAST_APP_BUTTONS_HOTFIX",
  "createdAt": "2026-06-17",
  "description": "Restores customer fast app quick buttons for products, offers/discounts, and reservations, and adds reservations tab/cards.",
  "databaseChanges": false,
  "files": [
    "components/customer-app/customer-fast-app-client.tsx"
  ],
  "runFromProjectRoot": "node BARNDAKSA_CUSTOMER_FAST_APP_BUTTONS_HOTFIX/apply-patch.cjs"
};

function fail(message) {
  console.error(`
[${PATCH_NAME}] ${message}
`);
  process.exit(1);
}

function findProjectRoot() {
  const candidates = [process.cwd(), path.dirname(__dirname), path.resolve(__dirname, "..")];
  for (const candidate of candidates) {
    if (candidate && fs.existsSync(path.join(candidate, "package.json"))) return candidate;
  }
  fail("ضع مجلد الباتش داخل جذر المشروع ثم شغل السكربت من جذر المشروع. لم أجد package.json.");
}

function writeFileSafe(projectRoot, relativePath, contentBuffer, backupRoot) {
  const cleanPath = relativePath.replaceAll("\\", "/");
  if (cleanPath.includes("..") || path.isAbsolute(cleanPath)) fail(`Unsafe patch path blocked: ${relativePath}`);

  const target = path.join(projectRoot, cleanPath);
  const backup = path.join(backupRoot, cleanPath);

  if (!fs.existsSync(path.join(projectRoot, "components", "customer-app"))) {
    fail("لم أجد components/customer-app داخل المشروع. تأكد أنك طبقت باتش Customer Fast App الأساسي أولًا.");
  }

  fs.mkdirSync(path.dirname(target), { recursive: true });
  if (fs.existsSync(target)) {
    fs.mkdirSync(path.dirname(backup), { recursive: true });
    fs.copyFileSync(target, backup);
  }
  fs.writeFileSync(target, contentBuffer);
  console.log(`✓ ${cleanPath}`);
}

const projectRoot = findProjectRoot();
const stamp = new Date().toISOString().replace(/[:.]/g, "-");
const backupRoot = path.join(projectRoot, ".barndaksa-patch-backups", `${PATCH_NAME}-${stamp}`);

console.log(`
Applying ${PATCH_NAME}...`);
console.log(`Project root: ${projectRoot}`);
console.log(`Backup root: ${backupRoot}
`);

for (const file of PATCH_PAYLOAD) {
  if (!file.path || file.encoding !== "base64" || typeof file.content !== "string") fail("Invalid embedded patch payload.");
  writeFileSafe(projectRoot, file.path, Buffer.from(file.content, "base64"), backupRoot);
}

console.log("\nDone. Next commands:");
console.log("npm exec tsc -- --noEmit");
console.log("npm run build");

if (PATCH_MANIFEST.databaseChanges === false) console.log("\nDatabase: no SQL migration required for this hotfix.");
